import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from "react-router-dom";
import Register from './Register';
import Home from "./Home";
import About from "./About";
import Login from "./Login";
import Profile from "./Profile";

import AdminLogin from "./admin/AdminLogin";
import AdminDashboard from "./admin/AdminDashboard";
import AdminProfile from "./admin/AdminProfile";
import ProtectedRoute from "./admin/ProtectedRoute";

function App() {
  return (
    <Router>
      <Navbar />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/profile" element={<Profile />} />

        {/* ADMIN ROUTES */}
        <Route path="/admin/login" element={<AdminLogin />} />
        <Route
          path="/admin/dashboard"
          element={
            <ProtectedRoute>
              <AdminDashboard />
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/profile"
          element={
            <ProtectedRoute>
              <AdminProfile />
            </ProtectedRoute>
          }
        />
      </Routes>
    </Router>
  );
}

// Navbar Component with Profile Dropdown
function Navbar() {
  const [user, setUser] = useState(null);
  const [admin, setAdmin] = useState(null);
  const [showDropdown, setShowDropdown] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    // Check if user is logged in
    const userData = localStorage.getItem('user');
    const adminData = localStorage.getItem('adminUser');

    if (userData) {
      setUser(JSON.parse(userData));
    }
    if (adminData) {
      setAdmin(JSON.parse(adminData));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    localStorage.removeItem('adminUser');
    setUser(null);
    setAdmin(null);
    setShowDropdown(false);
    navigate('/');
    window.location.reload(); // Refresh to update navbar
  };

  return (
    <nav style={navStyle}>
      <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
        <Link to="/" style={linkStyle}>Home</Link>
        <Link to="/about" style={linkStyle}>About</Link>

        {!user && !admin && (
          <>
            <Link to="/login" style={linkStyle}>Citizen Login</Link>
            <Link to="/admin/login" style={linkStyle}>Admin</Link>
          </>
        )}

        {admin && (
          <Link to="/admin/dashboard" style={linkStyle}>Dashboard</Link>
        )}
      </div>

      {/* Profile Dropdown */}
      {(user || admin) && (
        <div style={profileContainerStyle}>
          <button
            onClick={() => setShowDropdown(!showDropdown)}
            style={profileButtonStyle}
          >
            <div style={avatarStyle}>
              {user ? user.name?.charAt(0).toUpperCase() : admin?.name?.charAt(0).toUpperCase() || 'A'}
            </div>
            <span style={{ marginLeft: '8px' }}>
              {user ? user.name : admin?.name || 'Admin'}
            </span>
            <span style={{ marginLeft: '5px', fontSize: '12px' }}>▼</span>
          </button>

          {showDropdown && (
            <div style={dropdownStyle}>
              <div style={dropdownHeaderStyle}>
                <div style={avatarLargeStyle}>
                  {user ? user.name?.charAt(0).toUpperCase() : admin?.name?.charAt(0).toUpperCase() || 'A'}
                </div>
                <div>
                  <div style={{ fontWeight: 'bold' }}>
                    {user ? user.name : admin?.name || 'Admin'}
                  </div>
                  <div style={{ fontSize: '12px', color: '#888' }}>
                    {user ? user.email : admin?.email || 'admin@kdmc.gov'}
                  </div>
                  <div style={{ fontSize: '11px', color: '#667eea', marginTop: '3px' }}>
                    {admin ? '👑 Admin' : '👤 Citizen'}
                  </div>
                </div>
              </div>
              <hr style={{ margin: '10px 0', border: 'none', borderTop: '1px solid #eee' }} />
              <Link
                to={admin ? "/admin/profile" : "/profile"}
                style={dropdownItemStyle}
                onClick={() => setShowDropdown(false)}
              >
                📊 My Profile
              </Link>
              <button onClick={handleLogout} style={dropdownItemStyle}>
                🚪 Logout
              </button>
            </div>
          )}
        </div>
      )}
    </nav>
  );
}

/* ---------------- STYLES ---------------- */

const navStyle = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  padding: "15px 30px",
  background: "#111"
};

const linkStyle = {
  color: "#fff",
  textDecoration: "none",
  fontWeight: "bold"
};

const profileContainerStyle = {
  position: "relative"
};

const profileButtonStyle = {
  display: "flex",
  alignItems: "center",
  background: "transparent",
  border: "2px solid #667eea",
  borderRadius: "25px",
  padding: "6px 15px 6px 6px",
  color: "#fff",
  cursor: "pointer",
  fontSize: "14px",
  fontWeight: "bold",
  transition: "all 0.3s"
};

const avatarStyle = {
  width: "32px",
  height: "32px",
  borderRadius: "50%",
  background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  color: "#fff",
  fontWeight: "bold",
  fontSize: "16px"
};

const avatarLargeStyle = {
  width: "50px",
  height: "50px",
  borderRadius: "50%",
  background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  color: "#fff",
  fontWeight: "bold",
  fontSize: "24px",
  marginRight: "12px"
};

const dropdownStyle = {
  position: "absolute",
  top: "50px",
  right: "0",
  background: "#fff",
  borderRadius: "10px",
  boxShadow: "0 5px 20px rgba(0,0,0,0.3)",
  minWidth: "250px",
  padding: "15px",
  zIndex: 1000
};

const dropdownHeaderStyle = {
  display: "flex",
  alignItems: "center",
  marginBottom: "10px"
};

const dropdownItemStyle = {
  display: "block",
  width: "100%",
  padding: "10px",
  background: "transparent",
  border: "none",
  textAlign: "left",
  cursor: "pointer",
  color: "#333",
  textDecoration: "none",
  borderRadius: "5px",
  fontSize: "14px",
  transition: "background 0.2s"
};

export default App;
